def solve(s: String, order: Array[Long], k: Long): Long = {
  import scala.collection.mutable.ListBuffer

  val n = s.length
  val indices = order.map(_.toInt)
  val original = s.toCharArray
  val replaced = original.clone()

  // Function to count the number of valid substrings
  def countValidSubstrings(): Long = {
    var count = 0L
    val starIndices = ListBuffer[Int]()
    for (i <- 0 until n) {
      if (replaced(i) == '*') starIndices += i
    }

    if (starIndices.isEmpty) return 0

    var total = 0L
    for (i <- 0 until n) {
      if (replaced(i) == '*') {
        // All substrings ending at i that include this star
        total += i + 1
      } else {
        // Find the nearest star to the left
        var left = 0
        while (left < starIndices.length && starIndices(left) < i) left += 1
        if (left > 0) {
          // All substrings ending at i that include this star
          total += i - starIndices(left - 1)
        }
      }
    }
    total
  }

  // Binary search for the minimum time t
  var left = 0L
  var right = n - 1L
  var answer = -1L

  while (left <= right) {
    val mid = (left + right) / 2
    // Simulate replacing first mid elements in order
    for (i <- 0 until mid) {
      replaced(indices(i)) = '*'
    }
    val currentCount = countValidSubstrings()
    if (currentCount >= k) {
      answer = mid
      right = mid - 1
    } else {
      left = mid + 1
    }
    // Reset the replaced array for next iteration
    for (i <- 0 until n) {
      replaced(i) = original(i)
    }
  }

  answer
}
